SELECT DISTINCT company_ticker_symbol
FROM corporate_filings
WHERE STRFTIME('%Y', filing_date) = '2020';

SELECT ticker_symbol, SUM(employee_count) AS total_employees
FROM companies
GROUP BY ticker_symbol;

SELECT COUNT(*)
FROM company_index_membership
WHERE index_id = 1;

SELECT company_description, industry_classification, market_capitalization
FROM companies
WHERE ticker_symbol = 'AAPL';
